const promesaExitosa = new Promise((resolve, reject) => {
  resolve('listo');
});

const promesaFallida = new Promise((resolve, reject) => {
  reject('error de red');
});

// Para que el test pueda verificar los valores:
let valorExito;
let valorError;

promesaExitosa.then(v => { valorExito = v; });
promesaFallida.catch(e => { valorError = e; });

// Pequeño hack para esperar la microtask queue
await Promise.resolve();

let resultado;

await Promise.resolve(5)
  .then(n => n * 2)    // 10
  .then(n => n + 3)    // 13
  .then(n => { resultado = n; });

exercises.prompt:
Tienes dos promesas que simulan peticiones:

```js
const p1 = Promise.resolve('usuarios cargados');
const p2 = Promise.resolve('productos cargados');
```

Usa `Promise.all` para esperar ambas y asigna los resultados al array `datos`.

